20		async realLifeTest(query: RealLifeTestDto): Promise<Product[]> {
21			const start = process.hrtime();
22	
23			if (query.throwError) {
24				this.logger.error('Intentional error via throwError');
25				throw new BadRequestException('Requested error from the real-life test endpoint');
