63		async calculatePi(
64			query: HardTaskDto,
65		): Promise<{ pi: string; executionTimeMs: number }> {
66			const start = process.hrtime();
67	
68			if (query.throwError) {
69				this.logger.error('Intentional error via throwError');
70				throw new BadRequestException('Requested error from the hard task endpoint');
71			}
72	
73			try {
74				const iterations = 10_000;
75				let pi = 3.0;
76				let sign = 1;
77				for (let i = 2; i <= 2 * iterations; i += 2) {
78					pi += sign * (4 / (i * (i + 1) * (i + 2)));
79					sign *= -1;
80				}
81				const piString = pi.toFixed(49);
82	
83				const executionTimeMs = this.getElapsedMs(start);
