239				sizes: ['S', 'M', 'L', 'XL', 'XXL'].slice(0, Math.floor(Math.random() * 5) + 1),
240				status: getRandomItem(statuses),
241				style_type: getRandomItem(style_types),
242				product_type: getRandomItem(product_types),
243				style_card_image_url: `https://mms-images.staging.customink.com/mms/images/catalog/${this.randomString(32)}/styles/${product_id}/catalog_detail_image_medium.jpg`,
