246					Math.floor(Math.random() * 5) + 1,
247				),
248				sub_category_names: this.getRandomSubset(
249					sub_categories,
250					Math.floor(Math.random() * 5) + 1,
251				),
252				turn_time: Math.floor(Math.random() * 20) + 5,
253				rush_turn_time: Math.floor(Math.random() * 10) + 1,
254				default_unit_prices: this.generateRandomPrices(),
255				link: {
256					name: `Product #${product_id}`,
257					path: `/products/workwear-uniforms/work-jackets/product-${product_id}`,
258				},
259				colors: this.getRandomSubset(colors, Math.floor(Math.random() * 3) + 1),
260				objectID: product_id.toString(),
261			};
262	
263			return randomProduct;
264		}
