266		private getRandomSubset<T>(arr: T[], count: number): T[] {
267			if (!arr.length) return [];
268			const safeCount = Math.min(Math.max(count, 1), arr.length);
269			const copy = [...arr];
270			const result: T[] = [];
271			while (result.length < safeCount) {
272				const idx = Math.floor(Math.random() * copy.length);
273				const item = copy.splice(idx, 1)[0];
274				if (!item) result.push(item as T);
275			}
276			return result;
277		}
278	
279		private randomString(length: number): string {
280			const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
281			return Array.from({ length })
282				.map(() => chars[Math.floor(Math.random() * chars.length)])
283				.join('');
284		}
285	
286		private generateRandomPrices(): {
287			algorithm: string;
288			quantity: number;
289			price: string;
290		}[] {
291			const algorithms = ['default-2022-03-24', 'plus_5-2024-04-30', 'minus_5-2024-04-30'];
292			const quantities = [15, 20, 25, 50, 100, 500];
293			const prices: { algorithm: string; quantity: number; price: string }[] = [];
294	
295			for (const algorithm of algorithms) {
296				for (const quantity of quantities) {
297					if (Math.random() < 0.5) {
298						const base = 200 + Math.random() * 50;
299						const adjusted = base * (1 - quantity / 1000);
300						prices.push({
301							algorithm,
302							quantity,
303							price: adjusted.toFixed(2),
304						});
305					}
306				}
307			}
308	
309			return prices;
310		}
